#include <cstddef>
#include <omp.h>

/* In the vector `x` negate the odd values and divide the even values by 2.
   Example:

   input:  [16, 11, 12, 14, 1, 0, 5]
   output: [8, -11, 6, 7, -1, 0, -5]
*/
inline void negateOddsAndHalveEvens(std::vector<int> &x) {
    const std::size_t n = x.size();
    // Parallel work distribution: chunk size chosen to give good load balance
    const std::size_t chunk = (n + 7) / 8;  // 8 threads -> 8 chunks

#pragma omp parallel for schedule(static, chunk)
    for (std::size_t i = 0; i < n; ++i) {
        int val = x[i];
        // Use bit tests instead of modulo for speed
        if ((val & 1) == 0) {          // even
            x[i] = val >> 1;           // divide by 2
        } else {                       // odd
            x[i] = -val;
        }
    }
}
