/* Return the product of the vector x with every odd indexed element inverted.
   i.e. x_0 * 1/x_1 * x_2 * 1/x_3 * x_4 ...
   Example:
   input: [4, 2, 10, 4, 5]
   output: 25
*/
double productWithInverses(const std::vector<double>& x)
{
    // Direct accumulation keeps the computation in one pass
    // and allows the compiler to vectorise / parallelise it.
    double prod{1.0};

#pragma omp parallel for reduction(*:prod)
    for (std::size_t i = 0; i < x.size(); ++i)
    {
        // Even indices contribute directly, odd indices contribute their inverse.
        prod *= (i & 1) ? (1.0 / x[i]) : x[i];
    }

    return prod;
}
