#include <numeric>
#include <vector>
#include <execution>   // C++17 execution policies

// Compute the prefix sum of the vector `x` into `output`.
// The result is identical to the serial `std::inclusive_scan`.
inline void prefixSum(std::vector<int64_t> const& x,
                      std::vector<int64_t> &output) noexcept
{
    // Ensure output has the correct size
    output.resize(x.size());

    // Parallel inclusive scan (unsequenced to expose vectorization)
    std::inclusive_scan(
        std::execution::par_unseq,           // parallel, unsequenced policy
        x.begin(), x.end(),
        output.begin()
    );
}
