/* Count the number of edges in the directed graph defined by the
   adjacency matrix A (row‑major).  The result is the exact count
   as in the reference implementation. */
inline int edgeCount(std::vector<int> const& A, size_t N)
{
    int count = 0;

    // Parallelize over rows, using a two‑level loop for better cache usage
    #pragma omp parallel for reduction(+:count) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const int* row = A.data() + i * N;
        // inner loop unrolled manually to reduce branch mispredictions
        size_t j = 0;
        for (; j + 7 < N; j += 8)
        {
            count += row[j]   + row[j+1] + row[j+2] + row[j+3]
                    + row[j+4] + row[j+5] + row[j+6] + row[j+7];
        }
        // handle the remaining elements
        for (; j < N; ++j)
            count += row[j];
    }

    return count;
}
