#pragma once
#include <vector>
#include <limits>
#include <numeric>
#include <omp.h>

/*
 * Return the value of the smallest odd number in the vector `x`.
 * If no odd number exists, the result is `std::numeric_limits<int>::max()`.
 */
int smallestOdd(const std::vector<int> &x)
{
    if (x.empty())
        return std::numeric_limits<int>::max();

    // Parallel reduction with a custom operator that keeps the smallest odd value.
    int best = std::numeric_limits<int>::max();

    // We use a parallel loop with a separate thread‑local accumulator to avoid
    // contention on the shared variable `best`.
    #pragma omp parallel
    {
        int thread_best = std::numeric_limits<int>::max();

        #pragma omp for nowait
        for (std::size_t i = 0; i < x.size(); ++i)
        {
            int v = x[i];
            if ((v & 1) == 0)          // skip even values
                continue;

            if (v < thread_best)
                thread_best = v;
        }

        #pragma omp atomic
        if (thread_best < best)
            best = thread_best;
    }

    return best;
}
