/*
 * Compute the prefix sum array of the vector `x` and return its sum.
 * The direct computation is equivalent to:
 *   sum_{i=0}^{n-1} (sum_{j=0}^{i} x[j])
 * which can be rewritten as:
 *   sum_{j=0}^{n-1} x[j] * (n - j)
 *
 * This implementation performs the weighted sum in a single parallel
 * reduction, eliminating the need for an auxiliary array and
 * reducing cache traffic.
 */
inline int64_t sumOfPrefixSum(const std::vector<int64_t>& x) {
    const size_t n = x.size();
    int64_t result = 0;

    #pragma omp parallel for reduction(+:result) schedule(static)
    for (size_t i = 0; i < n; ++i) {
        result += x[i] * static_cast<int64_t>(n - i);
    }

    return result;
}
