48_sparse_la_sparse_axpy:
```cpp
#pragma once
#include <vector>

struct Element {
    size_t index;
    double  value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors.
   z is updated in place.  The implementation is a single linear
   merge of the sorted index lists – identical to the original
   algorithm but written with a few small optimisations that allow
   the compiler to generate faster instructions.
*/
inline void sparseAxpy(double alpha,
                       const std::vector<Element>& x,
                       const std::vector<Element>& y,
                       std::vector<double>& z)
{
    const size_t nx = x.size();
    const size_t ny = y.size();

    size_t ix = 0, iy = 0;

    /* Main merge loop --------------------------------------------------- */
    while (ix < nx && iy < ny) {
        const size_t idx_x = x[ix].index;
        const size_t idx_y = y[iy].index;
        /* collapse compares for the common case */
        if (idx_x < idx_y) {
            z[idx_x] += alpha * x[ix].value;
            ++ix;
        } else if (idx_x > idx_y) {
            z[idx_y] += y[iy].value;
            ++iy;
        } else {
            z[idx_x] += alpha * x[ix].value + y[iy].value;
            ++ix;
            ++iy;
        }
    }

    /* Remaining elements of x ------------------------------------------- */
    for ( ; ix < nx; ++ix)
        z[x[ix].index] += alpha * x[ix].value;

    /* Remaining elements of y ------------------------------------------- */
    for ( ; iy < ny; ++iy)
        z[y[iy].index] += y[iy].value;
}
