19_graph_shortest_path:
```cpp
#pragma once
#include <vector>
#include <limits>
#include <cstddef>
#include <cstring>

/* Return the length of the shortest path from source to dest in the undirected graph
 * defined by the adjacency matrix A (row‑major). The graph is assumed connected.
 */
inline int shortestPathLength(std::vector<int> const& A, std::size_t N, int source, int dest) {
    // The queue will be a simple ring buffer of node indices; distances are kept in a separate array.
    std::vector<int> dist(N, -1);
    std::vector<char> inqueue(N, 0);  // fast visited flag

    std::vector<int> queue(N);
    std::size_t head = 0, tail = 0;

    dist[source] = 0;
    inqueue[source] = 1;
    queue[tail++] = source;

    while (head != tail) {
        int u = queue[head++];
        if (head == N) head = 0;          // wrap around
        int du = dist[u] + 1;             // distance to neighbours

        /* Inline linear scan of the adjacency row. The matrix is stored
         * row‑major as A[u * N + v]. We unroll a bit to reduce branch
         * mispredictions on dense graphs.
         */
        std::size_t idx = u * N;
        for (std::size_t v = 0; v < N; ++v, ++idx) {
            if (A[idx] && !inqueue[v]) {
                inqueue[v] = 1;
                dist[v] = du;
                if (v == dest) return du;   // found destination
                queue[tail++] = static_cast<int>(v);
                if (tail == N) tail = 0;
            }
        }
    }
    return std::numeric_limits<int>::max();    // unreachable in a connected graph
}
