#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
   std::size_t row;
   std::size_t column;
   double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N.
   Example:
   input: alpha=0.5 beta=1.0 A=[{0,1,3}, {1,0,-1}] x=[-4, 2] y=[-1,1]
   output: y=[2, 3]
*/
inline void spmv(double alpha,
                 std::vector<COOElement> const& A,
                 std::vector<double> const& x,
                 double beta,
                 std::vector<double> &y,
                 std::size_t /*M*/, std::size_t /*N*/)
{
    const std::size_t n = y.size();

    /* Scale y by beta – parallel with static chunking to keep memory
       throughput high. */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        y[i] *= beta;
    }

    /* Accumulate contributions from A.
       Multiple elements can target the same row, so each
       write must be protected with an atomic update.  Since
       atomic<double> is not available in C++14/17, we use
       the OpenMP atomic clause on the target element. */
#pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < A.size(); ++k) {
        const auto &e = A[k];
        /* COO may contain out‑of‑range entries; guard against them. */
        if (e.row < n && e.column < x.size()) {
            const double add = alpha * e.value * x[e.column];
#pragma omp atomic
            y[e.row] += add;
        }
    }
}
