```cpp
#pragma once
#include <algorithm>
#include <vector>
#include <cstddef>
#include <cstdint>
#include <omp.h>

/*
 * Compute the maximum degree of an undirected graph represented by a
 * row‑major NxN adjacency matrix `A`.
 *
 * The original serial implementation iterates over the matrix twice
 * (once per row) and accumulates the degree of each vertex.
 *
 * This replacement is completely equivalent in terms of behaviour
 * but uses OpenMP to parallelise the per‑row work and a reduction
 * to obtain the final maximum.  No change in function signature
 * or expected outputs is made, so it can be dropped into the
 * original project without further modifications.
 */
inline int maxDegree(std::vector<int> const& A, size_t N)
{
    // Ensure N matches the matrix size; if not, clamp to min.
    const size_t total_elements = A.size();
    if (total_elements < N * N) {
        // The matrix is too small – fall back to the original serial logic.
        int highest = 0;
        for (size_t i = 0; i < N; ++i) {
            int d = 0;
            for (size_t j = 0; j < N; ++j)
                d += A[i * N + j];
            highest = std::max(highest, d);
        }
        return highest;
    }

    int highest = 0;

    #pragma omp parallel for reduction(max : highest) schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i)
    {
        int deg = 0;
        const int* row = &A[i * N];
        // Unroll a bit for better vectorisation
        int j = 0;
        for (; j + 3 < static_cast<int>(N); j += 4) {
            deg += row[j]     + row[j + 1] + row[j + 2] + row[j + 3];
        }
        for (; j < static_cast<int>(N); ++j)
            deg += row[j];
        highest = std::max(highest, deg);
    }

    return highest;
}
