/* Return the distance between the closest two elements in the vector x.
   Example:
   input: [7, 3, 9, 12, 31, 1]
   output: 2
*/
double closestPair(std::vector<double> const& x) {
    const std::size_t n = x.size();
    if (n < 2) return 0.0;

    double minDist = std::numeric_limits<double>::max();

    #pragma omp parallel for schedule(static) reduction(min:minDist)
    for (std::size_t i = 0; i < n; ++i) {
        const double xi = x[i];
        for (std::size_t j = i + 1; j < n; ++j) {
            const double d = std::fabs(xi - x[j]);
            if (d < minDist) minDist = d;
        }
    }
    return minDist;
}
