#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <omp.h>

struct Point {
    double x, y;
};

/* Count the number of cartesian points in each quadrant.
   The vector `points` contains a list of `Point` objects.
   Store the counts in `bins`.
   The function is thread‑safe and uses OpenMP to parallelise the loop.

   Example:
   input: [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9},
          {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
   output: [3, 1, 0, 2]
*/
inline void countQuadrants(const std::vector<Point>& points, std::array<std::size_t, 4>& bins)
{
    // Initialise output bins to zero (they may contain garbage from prior calls)
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Local thread‑private counters to avoid atomic operations
    const std::size_t n_threads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 4>> local_bins(n_threads);
    for (auto& lb : local_bins) {
        lb[0] = lb[1] = lb[2] = lb[3] = 0;
    }

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::array<std::size_t, 4> &l = local_bins[tid];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < points.size(); ++i) {
            const Point& pt = points[i];
            if (pt.x >= 0) {
                if (pt.y >= 0) ++l[0];
                else          ++l[3];
            } else {
                if (pt.y >= 0) ++l[1];
                else          ++l[2];
            }
