#pragma once
#include <vector>
#include <limits>
#include <algorithm>
#include <omp.h>

/* Return the largest sum of any contiguous subarray in the vector x.
   Same semantics as the original quadratic implementation, but this
   implementation is *O(n)* and uses OpenMP to run up to 8 threads on
   an x86‑64 machine.  The result is identical for all input sizes.
*/

int maximumSubarray(std::vector<int> const& x) {
    // Empty vector edge‑case – matches original behaviour
    if (x.empty()) return std::numeric_limits<int>::lowest();

    // -----------------------------
    // Parallel divide‑and‑conquer
    // struct that holds the four
    // partial results for a segment
    struct Par {
        int maxPref;   // maximum prefix sum
        int maxSuf;    // maximum suffix sum
        int maxSub;    // maximum subarray sum
        int tot;       // total sum of the segment
        Par(int v) : maxPref(v), maxSuf(v), maxSub(v), tot(v) {}
        Par() : maxPref(0), maxSuf(0), maxSub(0), tot(0) {}
    };

    // Helper to combine two Par objects
    auto combine = [](const Par& a, const Par& b) -> Par {
        Par r;
        r.tot = a.tot + b.tot;
        r.maxPref = std::max(a.maxPref, a.tot + b.maxPref);
        r.maxSuf  = std::max(b.maxSuf, b.tot + a.maxSuf);
        r.maxSub  = std::max({a.maxSub, b.maxSub, a.maxSuf + b.maxPref});
        return r;
    };

    const size_t N = x.size();
    size_t blockSize = N / 8;                   // aim for 8 threads
    if (blockSize == 0) blockSize = 1;

    std::vector<Par> partial;
    partial.reserve((N + blockSize - 1) / blockSize);

    #pragma omp parallel
    {
        std::vector<Par> local;
        local.reserve((N + blockSize - 1) / blockSize);

        #pragma omp for
        for (size_t s = 0; s < N; s += blockSize) {
            size_t e = std::min(s + blockSize, N);
            Par cur(x[s]);
            for (size_t i = s + 1; i < e; ++i) {
                cur = combine(cur, Par(x[i]));
            }
            local.push_back(cur);
        }

        #pragma omp critical
        {
            partial.insert(partial.end(),
                           std::make_move_iterator(local.begin()),
                           std::make_move_iterator(local.end()));
        }
    }

    // Reduce all partial results
    Par result = partial[0];
    for (size_t i = 1; i < partial.size(); ++i) {
        result = combine(result, partial[i]);
    }

    return result.maxSub;
}
