/*  Optimised component‑size calculation for a dense adjacency matrix.
    The algorithm uses an explicit stack instead of recursion, avoids
    repeated bounds checks, and keeps the visited flag in a packed byte
    array for cache friendliness.  The logic is identical to the
    reference implementation – only the inner loops were rewritten
    for speed.  No OpenMP parallelisation is added because a straightforward
    thread‑safe construction would require atomic updates or a lock per
    component and does not provide a noticeable speed advantage for the
    small to medium graph sizes typically used with dense matrices.
*/

inline void dfs_iterative(const std::vector<int8_t>& adj,
                          std::uint32_t start,
                          std::uint32_t N,
                          std::vector<char>& visited,
                          std::uint32_t& comp_size)
{
    // simple stack using a small fixed‑size array to minimise allocations
    std::vector<std::uint32_t> stack;
    stack.reserve(32);
    stack.push_back(start);
    visited[start] = 1;
    comp_size = 1;

    const std::uint32_t row_stride = N;
    while (!stack.empty()) {
        const std::uint32_t v = stack.back();
        stack.pop_back();

        const std::uint32_t offset = v * row_stride;
        for (std::uint32_t u = 0; u < N; ++u) {
            if (adj[offset + u] && !visited[u]) {
                visited[u] = 1;
                ++comp_size;
                stack.push_back(u);
            }
        }
    }
}

/* Return the number of vertices in the largest component of the graph
   defined by the adjacency matrix `A`.  `A` is stored in row‑major
   order, with entries castable to `int8_t` (0 or 1). */
int largestComponent(const std::vector<int>& A, std::size_t N)
{
    // convert to a packed byte matrix for faster access
    std::vector<int8_t> mat(A.begin(), A.end());

    std::vector<char> visited(N, 0);
    std::uint32_t max_size = 0;

    for (std::uint32_t i = 0; i < static_cast<std::uint32_t>(N); ++i) {
        if (!visited[i]) {
            std::uint32_t size = 0;
            dfs_iterative(mat, i, static_cast<std::uint32_t>(N), visited, size);
            if (size > max_size)
                max_size = size;
        }
    }
    return static_cast<int>(max_size);
}
