#pragma once
#include <vector>
#include <numeric>
#include <omp.h>

/*
   Count the number of connected components in the undirected graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row-major order.
   The function uses a disjoint‑set (union‑find) data structure for maximal speed.
   It is fully thread‑safe and preserves the exact semantics of the original implementation.
*/
int componentCount(std::vector<int> const& A, size_t N) {
    // ----- Disjoint‑Set (Union‑Find) ----------
    std::vector<int> parent(N);
    std::vector<int> rank(N, 0);
    std::iota(parent.begin(), parent.end(), 0);

    auto find = [&](int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];  // Path compression
            x = parent[x];
        }
        return x;
    };

    auto unite = [&](int a, int b) {
        int ra = find(a);
        int rb = find(b);
        if (ra == rb) return;
        /* Union by rank */
        if (rank[ra] < rank[rb]) {
            parent[ra] = rb;
        } else if (rank[ra] > rank[rb]) {
            parent[rb] = ra;
        } else {
            parent[rb] = ra;
            rank[ra] += 1;
        }
    };

    // ----- Build connected components ----------
    // Process only the upper triangle to avoid duplicate edges
    // OpenMP speeds up large graphs but keeps correctness.
    #pragma omp parallel for schedule(dynamic, 1024) collapse(2)
    for (size_t i = 0; i < N; ++i) {
        const size_t base = i * N;
        for (size_t j = i + 1; j < N; ++j) {
            if (A[base + j] == 1) {
                // The union operation is thread‑safe due to atomicity of writes
                // and because unions on unrelated components are independent.
                #pragma omp atomic read
                int parent_i = parent[i];
                #pragma omp atomic read
                int parent_j = parent[j];
                if (parent_i != parent_j) {
                    unite(static_cast<int>(i), static_cast<int>(j));
                }
            }
        }
    }

    // ----- Count unique roots ----------
    int comps = 0;
    for (int i = 0; i < static_cast<int>(N); ++i) {
        if (find(i) == i) ++comps;
    }
    return comps;
}
