#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

/* In‑place radix‑2 Cooley–Tukey FFT
 *   x   : input complex array (length N must be a power of 2)
 *   r & i : output real/imaginary parts
 * The implementation preserves the original behaviour, only the
 * internal ordering and parallelism are altered for speed.
 */
static inline void fft(std::vector<std::complex<double>> const& x,
                       std::vector<double> &r, std::vector<double> &i)
{
    const std::size_t N = x.size();
    // Reserve output space
    r.resize(N);
    i.resize(N);

    // ----- 1. Bit‑reversal permutation (in place) -----
    std::vector<std::complex<double>> a(x);        // copy for in‑place work
    for (std::size_t i = 0, j = 0; i < N; ++i) {
        if (i < j) std::swap(a[i], a[j]);
        std::size_t bit = N >> 1;
        while (j & bit) { j ^= bit; bit >>= 1; }
        j ^= bit;
    }

    // ----- 2. Pre‑compute twiddle factors for each stage -----
    const std::size_t stages = static_cast<std::size_t>(std::log2(N));
    std::vector<std::complex<double>> twiddles(N / 2);
    for (std::size_t k = 0; k < N / 2; ++k) {
        double angle = -2.0 * M_PI * k / N;
        twiddles[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    // ----- 3. Radix‑2 FFT (iterative) -----
    std::size_t stride = 1;
    for (std::size_t s = 0; s < stages; ++s, stride <<= 1) {
        const std::size_t half = stride;
        const std::size_t block = stride << 1;

#pragma omp parallel for schedule(static)
        for (std::size_t m = 0; m < N; m += block) {
            for (std::size_t j = 0; j < half; ++j) {
                std::size_t idx  = m + j;
                std::size_t idx2 = idx + half;
                std::complex<double> t = a[idx2] * twiddles[(j * N) / block];
                a[idx2] = a[idx] - t;
                a[idx]  += t;
            }
        }
    }

    // ----- 4. Split into real and imaginary parts -----
    #pragma omp parallel for
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
