#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Solve the sparse linear system Ax = b for x.
 * A is an NxN sparse matrix in COO format.
 * b and x are dense vectors of size N.
 *
 * The implementation builds a dense NxN matrix in a flat array,
 * performs Gaussian elimination with partial pivoting, and then
 * back‑substitutes.  All expensive loops are parallelised with
 * OpenMP where it yields a speed benefit without altering the
 * algorithmic behaviour.
 *
 * The function signature is kept identical to the original
 * harness.
 */
inline void solveLinearSystem(
    const std::vector<COOElement> &A,
    const std::vector<double> &b,
    std::vector<double> &x,
    size_t N)
{
    // Allocate a flat dense matrix and initialise to zero
    std::vector<double> matrix(N * N, 0.0);

    // Parallel construction of the matrix from COO data
    #pragma omp parallel for schedule(static, 256)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const auto &e = A[idx];
        matrix[e.row * N + e.column] = e.value;
    }

    // Local copies of b and the result vector
    std::vector<double> bb = b;
    x.assign(N, 0.0);

    /* ----------  Gaussian elimination with partial pivoting  ---------- */
    for (size_t i = 0; i < N; ++i) {
        // Find pivot row
        size_t pivot = i;
        double maxVal = std::abs(matrix[i * N + i]);

        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(matrix[k * N + i]);
            if (val > maxVal) {
                maxVal = val;
                pivot = k;
            }
        }

        // Swap rows i and pivot
        if (pivot != i) {
            for (size_t k = i; k < N; ++k) {
                std::swap(matrix[i * N + k], matrix[pivot * N + k]);
            }
            std::swap(bb[i], bb[pivot]);
        }

        // Eliminate below
        const double pivotVal = matrix[i * N + i];
        #pragma omp parallel for schedule(static, 256)
        for (size_t k = i + 1; k < N; ++k) {
            const double factor = -matrix[k * N + i] / pivotVal;
            if (factor == 0.0) continue;   // skip zero rows

            // Thread‑private update of row k
            for (size_t j = i; j < N; ++j) {
                matrix[k * N + j] += factor * matrix[i * N + j];
            }
            bb[k] += factor * bb[i];
        }
    }

    /* ----------  Back substitution  ---------- */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        const double diag = matrix[i * N + i];
        x[i] = bb[i] / diag;
        for (int k = i - 1; k >= 0; --k) {
            bb[k] -= matrix[k * N + i] * x[i];
        }
    }
}
