/*
 * Count the number of doubles in the vector `x` that have a fractional part
 * in [0, 0.25), [0.25, 0.5), [0.5, 0.75) and [0.75, 1). Store the counts in
 * `bins`. The algorithm is fully OpenMP‑parallel and branch‑less to minimise
 * pipeline stalls and branch mispredictions, while preserving the exact
 * semantics of the original implementation.
 */
inline void countQuartiles(const std::vector<double> &x, std::array<size_t, 4> &bins)
{
    // Initialise the output bins to zero
    bins.fill(0);

    // Local per‑thread bins to avoid a costly critical section per iteration.
    std::vector<std::array<size_t, 4>> threadBins;
    threadBins.resize(omp_get_max_threads());

    // Parallel loop over all elements
