    {
        const int threadId = omp_get_thread_num();
        auto &local = threadBins[threadId];

        // Each thread processes a contiguous block of the input array
#pragma omp for schedule(static)
        for (size_t i = 0; i < x.size(); ++i)
        {
            const double val  = x[i];
            // Replicate the exact two‑sided truncation behaviour of `(int)val`
            const double frac = val - static_cast<int>(val);

            // Branch‑less bin determination:
            //   0 <= frac < 0.25  → 0
            //   0.25 <= frac < 0.5 → 1
            //   0.5 <= frac < 0.75  → 2
            //   0.75 <= frac < 1    → 3
            const int bin = (frac >= 0.75) ? 3
                            : (frac >= 0.5) ? 2
                            : (frac >= 0.25) ? 1
                                            : 0;

