/*
 * Compute one iteration of a 3-point 1D Jacobi stencil on `input`.
 * Each element of `input` will be averaged with its two neighbours and
 * the result stored in the corresponding element of `output`.
 * i.e. output[i] = (input[i-1] + input[i] + input[i+1]) / 3.0,
 * with values outside the array treated as zero.
 *
 * The implementation is fully parallelised with OpenMP and avoids
 * branch mis‑predictions by handling the boundary cases in a separate
 * guard (the first and last elements).
 */
inline void jacobi1D(std::vector<double> const& input,
                     std::vector<double> &output)
{
    const std::size_t N = input.size();
    if (N == 0) return;

    // Ensure output has the right size (harness guarantees this, but be safe)
    if (output.size() != N) output.resize(N);

    // Handle boundaries explicitly to avoid branches inside the main loop
    output[0] = (input[0] + input[1]) / 3.0;
    output[N-1] = (input[N-2] + input[N-1]) / 3.0;

    // Main body – elements 1 … N-2
#pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i < N-1; ++i)
    {
        const double sum = input[i-1] + input[i] + input[i+1];
        output[i] = sum / 3.0;
    }
}
