/* Compute 0.5 * | (b-a) x (c-a) | without calling abs twice */
inline double triangleArea(const Point& a, const Point& b, const Point& c) {
    double cross = (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    return 0.5 * (cross >= 0 ? cross : -cross);
}

/* Return the area of the smallest triangle that can be formed by any 3 points. */
inline double smallestArea(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    /* Parallel reduction over the first index.
       Each thread works on a contiguous block of i values. */
#pragma omp parallel for schedule(static) reduction(min:minArea)
    for (std::ptrdiff_t i = 0; i <= static_cast<std::ptrdiff_t>(n - 3); ++i) {
        const Point* pi = &points[i];
        for (std::size_t j = i + 1; j <= n - 2; ++j) {
            const Point* pj = &points[j];
            for (std::size_t k = j + 1; k < n; ++k) {
                const double area = triangleArea(*pi, *pj, points[k]);
                if (area < minArea) {
                    minArea = area;
                    if (minArea == 0.0) {           // can't get smaller
                        /* break all loops by setting index to end */
                        j = n; k = n;
                    }
                }
            }
        }
    }
    return minArea;
}
