/* 1‑based neighbor XOR: a cell becomes 1 iff exactly one of its
 * four direct (N,S,E,W) neighbors contains a 1.  The input and
 * output are stored in row‑major order as a single contiguous
 * vector of ints.  The function must preserve the exact behaviour
 * of the reference implementation, but is allowed to use OpenMP
 * for parallelism and any other optimisation tricks.
 */
inline void cellsXOR(const std::vector<int> &input,
                     std::vector<int> &output,
                     const std::size_t N) noexcept
{
    // Ensure output has the same size as input
    if (output.size() != N * N) output.resize(N * N);

    const int* restrict in  = input.data();
    int* restrict out = output.data();

    // 2‑thread per row level parallelism -------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        const std::size_t row_offset = i * N;
        // pointers to the current row and its neighbours
        const int* const cur  = in  + row_offset;
        const int* const nbor = in  + (i > 0   ? row_offset - N : row_offset);
        const int* const sb   = in  + (i < N-1 ? row_offset + N : row_offset);

        int* const out_row = out + row_offset;

        for (std::size_t j = 0; j < N; ++j)
        {
            // count neighbours efficiently with bitwise tricks
            int cnt = 0;

            // north, south, west, east
            cnt += (i > 0   && nbor[j]   == 1) ? 1 : 0;
            cnt += (i < N-1 && sb [j]    == 1) ? 1 : 0;
            cnt += (j > 0   && cur[j-1] == 1) ? 1 : 0;
            cnt += (j < N-1 && cur[j+1] == 1) ? 1 : 0;

            out_row[j] = (cnt == 1) ? 1 : 0;
        }
    }
}
