     *     ordering because the input is not assumed to be sorted.
     * ------------------------------------------------------------------ */
    std::vector<size_t> row_ptr(N + 1, 0);
    for (auto const& e : A) ++row_ptr[e.row + 1];
    for (size_t i = 0; i < N; ++i) row_ptr[i + 1] += row_ptr[i];

    std::vector<size_t> col_idx(row_ptr[N]);
    std::vector<double> vals(row_ptr[N]);

    std::vector<size_t> counter = row_ptr;      // temporary counts
    for (auto const& e : A) {
        size_t pos = counter[e.row]++;
        col_idx[pos] = e.column;
        vals[pos]   = e.value;
    }

    /* ------------------------------------------------------------------
     *  2. Allocate dense L and U; initialise to zero.
     * ------------------------------------------------------------------ */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* ------------------------------------------------------------------
     *  3. Doolittle LU (numerical kernel with minimal allocations).  All
     *     the inner work of the loops is vectorisable; a reduction over
     *     k is replaced by a manual loop to allow OpenMP parallelisation
     *     over the outer i/j loops.
     * ------------------------------------------------------------------ */
#pragma omp parallel for schedule(dynamic, 1) collapse(2) if (N > 128)
    for (size_t i = 0; i < N; ++i) {
        // Pre‑lookup the non‑zero entries of row i of A
        size_t row_start = row_ptr[i];
        size_t row_end   = row_ptr[i + 1];

        for (size_t j = 0; j < N; ++j) {
            double a_ij = 0.0;
            /* locate A(i,j) if present */
            for (size_t idx = row_start; idx < row_end; ++idx) {
                if (col_idx[idx] == j) { a_ij = vals[idx]; break; }
                if (col_idx[idx] > j)   break;
            }

            /* Upper triangle (j >= i) */
            if (j >= i) {
                double sum = a_ij;
                for (size_t k = 0; k < i; ++k)
                    sum -= L[i * N + k] * U[k * N + j];
                U[i * N + j] = sum;
            }

            /* Lower triangle (i > j) */
            if (i > j) {
                double sum = a_ij;
                for (size_t k = 0; k < j; ++k)
                    sum -= L[i * N + k] * U[k * N + j];
                L[i * N + j] = sum / U[j * N + j];
            }

            /* Diagonal of L is 1 */
            if (i == j) L[i * N + j] = 1.0;
        }
    }
}
