//--------- Helper: precompute bit reversal indices --------------------------------
static std::vector<uint32_t> bit_reverse_indices(uint32_t n) {
    uint32_t m = 0;
    while ((1u << m) < n) ++m;               // m = log2(n)
    std::vector<uint32_t> idx(n);
    for (uint32_t i = 0; i < n; ++i) {
        uint32_t rev = 0;
        for (uint32_t j = 0; j < m; ++j)
            if (i & (1u << j))
                rev |= (1u << (m - 1 - j));
        idx[i] = rev;
    }
    return idx;
}

//--------- Helper: precompute twiddle factors ------------------------------------
static std::vector<std::complex<double>> twiddle_factors(uint32_t n) {
    std::vector<std::complex<double>> w(n / 2);
    const double pi = M_PI;
    for (uint32_t k = 0; k < n / 2; ++k)
        w[k] = std::polar(1.0, -2.0 * pi * k / n);
    return w;
}

//--------- Main FFT ---------------------------------------------------------------
void fft(const std::vector<std::complex<double>>& x,
         std::vector<std::complex<double>>& output) {
    const uint32_t N = static_cast<uint32_t>(x.size());
    if (N == 0) { output.clear(); return; }

    // Ensure N is a power of two
    if ((N & (N - 1)) != 0) {
        throw std::invalid_argument("fft size must be power of two");
    }

    output = x;

    const auto idx = bit_reverse_indices(N);
    // Bit‑reversal permutation
    #pragma omp parallel for schedule(static)
    for (uint32_t i = 0; i < N; ++i) {
        uint32_t j = idx[i];
        if (j > i) {
            std::swap(output[i], output[j]);
        }
    }

    const auto w = twiddle_factors(N);

    // Iterative Cooley‑Tukey (Radix‑2)
    for (uint32_t len = 2; len <= N; len <<= 1) {
        uint32_t half = len >> 1;
        uint32_t step = N / len;
        #pragma omp parallel for schedule(static)
        for (uint32_t i = 0; i < N; i += len) {
            for (uint32_t j = 0; j < half; ++j) {
                std::complex<double> u = output[i + j];
                std::complex<double> v = output[i + j + half] * w[j * step];
                output[i + j] = u + v;
                output[i + j + half] = u - v;
            }
        }
    }
}
