/* Return the k‑th smallest element of vector `x`.  The function
   keeps the original behaviour: it produces the same result as
   sorting the vector and selecting the element at position `k-1`.
   Complexity is reduced from O(n log n) to average O(n). */
int findKthSmallest(std::vector<int> const& x, int k) {
    // Make a local copy to preserve the original vector.
    std::vector<int> x_copy = x;
    // nth_element partially sorts so that the element at the
    // requested position is the one that would be there
    // after a full sort; all smaller elements are before it.
    std::nth_element(x_copy.begin(), x_copy.begin() + (k - 1), x_copy.end());
    return x_copy[k - 1];
