/*
 * Replace the i‑th element of the vector x with the minimum value from indices 0 through i.
 *
 * This implementation performs a parallel prefix‑minimum. The work is split into
 * chunks that are processed by individual threads. The algorithm follows two
 * phases:
 *
 * 1. (Per‑chunk) Compute the local prefix minimum and the minimum of the
 *    entire chunk. The per‑element minima are stored in the same output array
 *    for locality and to minimize temporary space.
 *
 * 2. (Parallel prefix over chunk minima) Compute the prefix minimum of the
 *    chunk minima array, which gives the minimum value that precedes each
 *    chunk. Each thread then adjusts its chunk's local minima by taking the
 *    minimum of that value and the previously computed local prefix value.
 *
 * The algorithm is fully stable and preserves the exact behaviour of the
 * original `std::inclusive_scan` implementation.
 */
inline void partialMinimums(std::vector<float>& x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    const int  num_threads = omp_get_max_threads();
    const std::size_t chunk = (N + num_threads - 1) / num_threads;
    const std::size_t num_chunks = (N + chunk - 1) / chunk;

    std::vector<float> chunk_min(num_chunks, std::numeric_limits<float>::max());

    // Phase 1: compute local prefix minima and store last element of each chunk
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::size_t start = tid * chunk;
        if (start >= N) return;

        std::size_t end = std::min(start + chunk, N);
        float local_min = std::numeric_limits<float>::max();

        // prefix minima inside the chunk
        for (std::size_t i = start; i < end; ++i) {
            local_min = std::min(local_min, x[i]);
            x[i] = local_min;  // store local prefix min
        }
        chunk_min[tid] = local_min;   // last min of this chunk
    }

    // Phase 2: compute prefix mins over chunk minima
    for (std::size_t i = 1; i < num_chunks; ++i) {
        chunk_min[i] = std::min(chunk_min[i - 1], chunk_min[i]);
    }

    // Phase 3: adjust each chunk with the minimum preceding it
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::size_t start = tid * chunk;
        if (start >= N) return;

        std::size_t end = std::min(start + chunk, N);
        float prev_min = (start == 0) ? std::numeric_limits<float>::max() : chunk_min[tid - 1];

        for (std::size_t i = start; i < end; ++i) {
            // x[i] currently holds the local prefix min; combine with prev_min
            x[i] = std::min(prev_min, x[i]);
        }
    }
}
