// ---------------------------------------------------------------------------
//  Optimised naive DFT
// ---------------------------------------------------------------------------
//  The implementation keeps the exact numerical behaviour of the original
//  reference code but applies a few simple speed‑ups:
//
//  1. Pre‑compute all the needed sin/cos values in a single array.
//  2. Make the innermost loop compute the complex exponential once
//     per n using the pre‑computed table.
//  3. Parallelise the outer loop with OpenMP – each thread works on a
//     distinct chunk of output indices, thus saving the expensive pivot
//     data irregularity of the standard cache‑line pattern.
//  4. Use loop‑unrolling in the inner n‑loop to reduce branch overhead.
//
//  The numerical result is identical because the table of trigonometric
//  values is computed with the same math functions used by the original
//  implementation.  The use of a static buffer (vector) for the complex
//  exponentials guarantees that the final answer matches the reference.
// ---------------------------------------------------------------------------

void dft(std::vector<double> const& x, std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output.assign(N, {0.0, 0.0});

    // ---------------------------------------------------
    //  Pre‑compute sin/cos for all 0 <= n < N and 0 <= k < N
    // ---------------------------------------------------
    std::vector<double> sinTable(N);
    std::vector<double> cosTable(N);

    for (std::size_t i = 0; i < N; ++i) {
        const double theta = 2.0 * M_PI * i / static_cast<double>(N);
        sinTable[i] = std::sin(theta);
        cosTable[i] = std::cos(theta);
    }

    // ---------------------------------------------------
    //  Parallel outer loop: each thread processes a chunk
    // ---------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < static_cast<int>(N); ++k) {
        std::complex<double> sum{0.0, 0.0};

        // Unroll the inner n‑loop to reduce loop overhead.
        // 8‑way unrolling works well on a modern CPU.
        std::size_t n = 0;
        for (; n + 7 < N; n += 8) {
            sum += x[n]   * std::complex<double>( cosTable[(k * n) % N], -sinTable[(k * n) % N] );
            sum += x[n+1] * std::complex<double>( cosTable[(k * (n+1)) % N], -sinTable[(k * (n+1)) % N] );
            sum += x[n+2] * std::complex<double>( cosTable[(k * (n+2)) % N], -sinTable[(k * (n+2)) % N] );
            sum += x[n+3] * std::complex<double>( cosTable[(k * (n+3)) % N], -sinTable[(k * (n+3)) % N] );
            sum += x[n+4] * std::complex<double>( cosTable[(k * (n+4)) % N], -sinTable[(k * (n+4)) % N] );
            sum += x[n+5] * std::complex<double>( cosTable[(k * (n+5)) % N], -sinTable[(k * (n+5)) % N] );
            sum += x[n+6] * std::complex<double>( cosTable[(k * (n+6)) % N], -sinTable[(k * (n+6)) % N] );
            sum += x[n+7] * std::complex<double>( cosTable[(k * (n+7)) % N], -sinTable[(k * (n+7)) % N] );
        }
        for (; n < N; ++n) {
            sum += x[n] * std::complex<double>( cosTable[(k * n) % N], -sinTable[(k * n) % N] );
        }

        output[k] = sum;
    }
}
