/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither.*/
bool xorContains(const std::vector<int> &x, const std::vector<int> &y, int val) {
    // Fast linear search with early exit; parallelized if vectors are large
    bool foundInX = false, foundInY = false;

    // Search x
    #pragma omp parallel for
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (!foundInX && x[i] == val) {
            #pragma omp atomic write
            foundInX = true;
        }
    }

    // Search y
    #pragma omp parallel for
    for (std::size_t i = 0; i < y.size(); ++i) {
        if (!foundInY && y[i] == val) {
            #pragma omp atomic write
            foundInY = true;
        }
    }

    return foundInX ^ foundInY;
}
