#pragma once
#include <vector>
#include <algorithm>

struct Point {
    double x, y;
};

/*
 * Compute the convex hull of a set of points (Monotone chain).
 *
 * The algorithm runs in O(n log n) because of the initial sort.
 * It is implemented in place with minimal allocations and uses only
 * small temporary storage.
 */
static inline double cross(const Point& a, const Point& b, const Point& c) noexcept
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull)
{
    const std::size_t n = points.size();
    if (n < 3) {                 // degenerate cases
        hull = points;
        return;
    }

    std::vector<Point> sorted(points);
    // Sorting by (x, y) – the compiler can inline the comparator
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    std::vector<Point> tmp;
    tmp.reserve(2 * n);          // upper + lower hull

    // Lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (tmp.size() >= 2 &&
               cross(tmp[tmp.size() - 2], tmp[tmp.size() - 1], sorted[i]) <= 0.0)
            tmp.pop_back();
        tmp.push_back(sorted[i]);
    }

    // Upper hull – skip first and last point of the lower hull to
    // avoid duplication
    const std::size_t lowerSize = tmp.size();
    for (std::size_t i = n - 1; i > 0; --i) {
        while (tmp.size() > lowerSize &&
               cross(tmp[tmp.size() - 2], tmp[tmp.size() - 1], sorted[i - 1]) <= 0.0)
            tmp.pop_back();
        tmp.push_back(sorted[i - 1]);
    }

    // Remove the last point (equal to the first one)
    if (!tmp.empty())
        tmp.pop_back();

    hull = std::move(tmp);
}
