#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>
#include <omp.h>

// Lightweight point structure
struct Point {
    double x, y;
};

// Helper inline functions for speed
inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

inline double dist(const Point& a, const Point& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Return the perimeter of the smallest convex polygon that contains all
 * the points in the vector points.
 */
double convexHullPerimeter(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Make a local copy to sort
    std::vector<Point> pts = points;

    // Sort lexicographically by (x, y)
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b) {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // Build convex hull using monotone chain (O(n))
    std::vector<Point> hull;
    hull.reserve(2 * n); // upper bound

    // Lower hull
    for (const Point& p : pts) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], p) <= 0.0)
            hull.pop_back();
        hull.push_back(p);
    }

    // Upper hull
    std::size_t lower_size = hull.size() + 1; // remember starting point
    for (std::size_t i = n; i-- > 1;) {
        const Point& p = pts[i];
        while (hull.size() >= lower_size &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], p) <= 0.0)
            hull.pop_back();
        hull.push_back(p);
    }

    // The last point is the same as the first one; remove it
    if (!hull.empty())
        hull.pop_back();

    // Compute perimeter using a parallel loop (OpenMP)
    double perim = 0.0;
    #pragma omp parallel for reduction(+:perim)
    for (std::size_t i = 0; i < hull.size(); ++i) {
        const Point& a = hull[i];
        const Point& b = hull[(i + 1) % hull.size()];
        perim += dist(a, b);
    }

    return perim;
}
