#pragma once
#include <vector>
#include <cstddef>
#include <cstring>   // for std::memset
#include <omp.h>

/* Optimised 5‑point 2‑D Jacobi stencil.
 * The implementation keeps the exact semantics of the original routine
 * (zero bordering elements, NxN row‑major storage) while using:
 *   • OpenMP parallelisation (collapsed 2‑loop)
 *   • Pointer arithmetic and loop unrolling
 *   • Simple boundary padding trick to avoid boundary checks in the hot loop
 */
inline void jacobi2D(
    const std::vector<double>& input,
    std::vector<double>& output,
    const size_t N)
{
    // Allocate a padded input buffer (size (N+2) x N)
    const size_t padded_cols = N;
    const size_t padded_rows = N + 2;                        // two extra rows for top/bottom padding
    const size_t buf_size   = padded_rows * padded_cols;    // N+2 rows
    double* padded = static_cast<double*>(std::aligned_alloc(64, buf_size * sizeof(double)));
    if (!padded) throw std::bad_alloc();

    // Initialise buffer to zero
    std::memset(padded, 0, buf_size * sizeof(double));

    // Copy the original data into the centre of the padded buffer.
    // Row i of input -> row i+1 of padded (skip first padded row)
    for (size_t i = 0; i < N; ++i) {
        std::memcpy(padded + (i + 1) * padded_cols,
                    input.data() + i * N,
                    N * sizeof(double));
    }

    // OpenMP parallelised collapsed loop: i over rows, j over columns.
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t in_row = (i + 1) * padded_cols;   // row in padded buffer
        const size_t out_idx = i * N;
        const double* row_above      = padded + in_row - padded_cols;
        const double* row_same     = padded + in_row;
        const double* row_below     = padded + in_row + padded_cols;

        for (size_t j = 0; j < N; ++j) {
            // Sum the five values
            double sum = *row_above     + *row_same     + *row_below
                       + row_same[j-1]   + row_same[j+1];
            output[out_idx + j] = sum * 0.2;   // divide by 5
        }
    }

    std::free(padded);
}
