#include <cstdint>
#include <omp.h>

#if !defined(M_PI)
# define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------
// In‑place radix‑2 Cooley‑Tukey FFT (forward)
// -----------------------------------------------------------
static void fft_inplace(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // Bit‑reversal permutation
    std::size_t logN = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    std::size_t rev = 0;
    for (std::size_t i = 0; i < N; ++i)
    {
        if (i < rev) std::swap(x[i], x[rev]);

        std::size_t mask = N >> 1;
        while (rev & mask)
        {
            rev ^= mask;
            mask >>= 1;
        }
        rev ^= mask;
    }

    // Pre‑compute twiddle factors
    std::vector<std::complex<double>> w(N / 2);
    for (std::size_t k = 0; k < N / 2; ++k)
    {
        double angle = -2 * M_PI * k / static_cast<double>(N);
        w[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    // FFT stages
    for (std::size_t len = 2; len <= N; len <<= 1)
    {
        std::size_t half = len >> 1;
        std::size_t step = N / len;

        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += len)
        {
            for (std::size_t j = 0; j < half; ++j)
            {
                std::complex<double> t = w[j * step] * x[i + j + half];
                std::complex<double> u = x[i + j];
                x[i + j] = u + t;
                x[i + j + half] = u - t;
            }
        }
    }
}

// -----------------------------------------------------------
// In‑place radix‑2 Cooley‑Tukey FFT (inverse)
// -----------------------------------------------------------
static void ifft_inplace(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // Conjugate
    #pragma omp parallel for
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    // Forward FFT
    fft_inplace(x);

    // Conjugate again
    #pragma omp parallel for
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    // Scale
    const double invN = 1.0 / static_cast<double>(N);
    #pragma omp parallel for
    for (std::size_t i = 0; i < N; ++i)
        x[i] *= invN;
}

// -----------------------------------------------------------
// Public API (keeps original signature)
// -----------------------------------------------------------
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    fft_inplace(x);
}

inline void ifft(std::vector<std::complex<double>>& x)
{
    ifft_inplace(x);
}
