// original serial algorithm.
size_t findClosestToPi(std::vector<double> const& x) {
    if (x.empty()) {
        return 0; // undefined behavior for empty input, keep original behaviour
    }

    size_t best_idx = 0;
    double best_diff = std::abs(x[0] - M_PI);

