    // Parallel reduction over a pair (diff, index).
    // Each thread maintains a local minimum diff and corresponding index.
    size_t local_idx = best_idx;
    double local_diff = best_diff;

    #pragma omp parallel
    {
        size_t thread_idx = best_idx;
        double thread_diff = best_diff;

        #pragma omp for nowait
        for (std::size_t i = 1; i < x.size(); ++i) {
            double d = std::abs(x[i] - M_PI);
            if (d < thread_diff) {
                thread_diff = d;
                thread_idx = i;
            }
        }

        // Update global minimum atomically.
        #pragma omp critical
        {
            if (thread_diff < local_diff) {
                local_diff = thread_diff;
                local_idx = thread_idx;
            }
        }
    }

    best_idx = local_idx;
    best_diff = local_diff;
#endif

    return best_idx;
}
