static constexpr int edgeKernel[3][3] = { {-1, -1, -1},
                                          {-1,  8, -1},
                                          {-1, -1, -1} };

/* Convolve the edge kernel with a grayscale image.
   Parameters:
     - imageIn : input image in row-major order, size N×N
     - imageOut: buffer to write the result into (must be pre‑allocated of size N×N)
     - N      : image dimension
   The algorithm uses 0 for out‑of‑bounds pixels and clamps the result
   to the range [0, 255].
   The implementation is fully parallelized with OpenMP and avoids
   unnecessary bounds checks for inner loops.
*/
void convolveKernel(const std::vector<int>& imageIn,
                    std::vector<int>& imageOut,
                    size_t N)
{
    /* Work on raw pointers for speed */
    const int*  in  = imageIn.data();
    int*        out = imageOut.data();

    /* Parallel over the whole image */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t iN = i * N;
        for (size_t j = 0; j < N; ++j)
        {
            int sum = 0;

            /* Manual unrolling of the 3×3 kernel for cache friendliness */
            // row i-1
            if (i > 0) {
                const size_t upIdx = (i-1) * N;
                sum += edgeKernel[0][0] * in[upIdx + (j-1)] * ((j > 0)      );
                sum += edgeKernel[0][1] * in[upIdx +  j]            * (1);
                sum += edgeKernel[0][2] * in[upIdx + (j+1)] * ((j+1<N)  );
            }
            // row i
            {
                const size_t midIdx = iN;
                sum += edgeKernel[1][0] * in[midIdx + (j-1)] * ((j > 0)      );
                sum += edgeKernel[1][1] * in[midIdx +  j]            * (1);
                sum += edgeKernel[1][2] * in[midIdx + (j+1)] * ((j+1<N)  );
            }
            // row i+1
            if (i+1 < N) {
                const size_t downIdx = (i+1) * N;
                sum += edgeKernel[2][0] * in[downIdx + (j-1)] * ((j > 0)      );
                sum += edgeKernel[2][1] * in[downIdx +  j]            * (1);
                sum += edgeKernel[2][2] * in[downIdx + (j+1)] * ((j+1<N)  );
            }

            /* Clamp to [0, 255] */
            out[iN + j] = static_cast<int>(std::min(255, std::max(0, sum)));
        }
    }
}
