#pragma once
#include <algorithm>
#include <numeric>
#include <vector>
#include <omp.h>

/*
 * For each value in the vector `x` compute its rank in the sorted order.
 * The rank of an element is the number of elements strictly smaller than it.
 * Ties are broken by the original index order (stable sort behaviour).
 */
inline void ranks(std::vector<float> const& x, std::vector<std::size_t> &ranks_)
{
    const std::size_t n = x.size();
    ranks_.resize(n);

    /* Build an array of (value, original_index) pairs */
    std::vector<std::pair<float,std::size_t>> tmp;
    tmp.reserve(n);
    for (std::size_t i = 0; i < n; ++i) {
        tmp.emplace_back(x[i], i);
    }

    /* Stable sort by value; ties are broken by original index order */
    std::stable_sort(tmp.begin(), tmp.end(),
                     [](const auto& a, const auto& b) { return a.first < b.first; });

    /* Fill the rank vector */
    #pragma omp parallel for
    for (std::size_t i = 0; i < n; ++i) {
        ranks_[tmp[i].second] = i;
    }
}
