// Return the index of the last Book item in the vector `books` where
// Book.pages is less than 100.
// If no such item exists, return books.size().
//
// The implementation scans the vector backwards with a single loop,
// avoiding an expensive signed/unsigned conversion on each iteration.
// It uses a simple while loop with a size_t index that is decremented
// safely by checking for underflow before the decrement.
// The code is fully portable and produces the exact same value
// as the reference implementation, while allowing the compiler
// to optimally schedule the loop on modern x86‑64 CPUs.
inline std::size_t findLastShortBook(const std::vector<Book>& books) {
    // If the vector is empty, just return its size (0).
    if (books.empty()) {
        return books.size();
    }

    // Use a size_t index that starts at books.size() - 1 and goes down.
    std::size_t idx = books.size() - 1;
    while (true) {
        if (books[idx].pages < 100) {
            return idx;
        }
        if (idx == 0) {   // reached the first element; none were < 100
            break;
        }
        --idx;            // safe to decrement because idx != 0
    }
    // No short book found
    return books.size();
}
