#pragma once
#include <vector>
#include <limits>
#include <algorithm>
#include <cmath>
#include <omp.h>

struct Point {
    double x, y;
};

/* squared distance – no sqrt needed inside the algorithm */
inline double dist2(Point const& a, Point const& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

/* Recursive divide‑and‑conquer helper.
   points[l..r) are sorted by x.
   The function returns the minimal squared distance in this interval
   and keeps points sorted by y in the same range. */
static double closestPairRec(std::vector<Point>& points, int l, int r, std::vector<Point>& aux) {
    int n = r - l;
    if (n <= 3) {                       // brute‑force
        double best = std::numeric_limits<double>::max();
        for (int i = l; i < r; ++i)
            for (int j = i + 1; j < r; ++j)
                best = std::min(best, dist2(points[i], points[j]));
        std::sort(points.begin() + l, points.begin() + r,
                  [](Point const& a, Point const& b){ return a.y < b.y; });
        return best;
    }

    int mid = l + n / 2;
    double midx = points[mid].x;

    /* parallel divide */
    double leftBest, rightBest;
#pragma omp task shared(points, aux) firstprivate(mid) untied
    leftBest = closestPairRec(points, l, mid, aux);
#pragma omp task shared(points, aux) firstprivate(mid) untied
    rightBest = closestPairRec(points, mid, r, aux);
#pragma omp taskwait
    double best = std::min(leftBest, rightBest);

    /* merge by y */
    std::inplace_merge(points.begin() + l, points.begin() + mid, points.begin() + r,
                       [](Point const& a, Point const& b){ return a.y < b.y; });

    /* build strip of points within sqrt(best) of the middle line */
    double d = std::sqrt(best);
    int sz = 0;
    for (int i = l; i < r; ++i)
        if (std::abs(points[i].x - midx) <= d)
            aux[sz++] = points[i];

    /* check only the next 7 points in the strip */
    for (int i = 0; i < sz; ++i)
        for (int j = i + 1; j < sz && (aux[j].y - aux[i].y) <= d; ++j)
            best = std::min(best, dist2(aux[i], aux[j]));

    return best;
}

/* Public API – exactly the same signature as the original */
double closestPair(std::vector<Point> const& points) {
    if (points.size() < 2) return 0.0;

    /* copy and sort once by x */
    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(),
              [](Point const& a, Point const& b){ return a.x < b.x; });

    std::vector<Point> aux(pts.size());
    double bestSq;

#pragma omp parallel
    {
#pragma omp single nowait
        {
            bestSq = closestPairRec(pts, 0, (int)pts.size(), aux);
        }
    }

    return std::sqrt(bestSq);
}
