#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
inline void solveLinearSystem(std::vector<double> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              std::size_t N) noexcept
{
    // Guard against degenerate input
    if (N == 0) return;

    // Allocate working copies
    std::vector<double> A_copy(A);
    std::vector<double> b_copy(b);

    // Gaussian elimination (forward elimination)
    for (std::size_t i = 0; i + 1 < N; ++i) {
        double const* row_i_ptr = A_copy.data() + i * N + i;
        double        pivot     = *row_i_ptr;

        // If pivot is zero we cannot proceed (singular matrix)
        if (pivot == 0.0) return;

        double const* col_i_ptr = A_copy.data() + i * N;
        double          b_i     = b_copy[i];

#pragma omp parallel for schedule(static) if (N > 64)
        for (std::size_t j = i + 1; j < N; ++j) {
            std::size_t idx_j_i = j * N + i;
            double const* row_j_ptr = A_copy.data() + j * N;
            double factor = A_copy[idx_j_i] / pivot;

            // Update row j
            for (std::size_t k = i; k < N; ++k) {
                row_j_ptr[k] -= factor * col_i_ptr[k - i];
            }
            // Update right‑hand side
            b_copy[j] -= factor * b_i;
        }
    }

    // Back substitution
    for (std::size_t ii = N; ii-- > 0;) {
        std::size_t i = ii;
        double sum = 0.0;
        const double* row_i = A_copy.data() + i * N;
        for (std::size_t j = i + 1; j < N; ++j) {
            sum += row_i[j] * x[j];
        }
        x[i] = (b_copy[i] - sum) / row_i[i];
    }
}
