#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Factorize the matrix A into A = LU where L is lower triangular and U is upper triangular.
   The result is stored in-place in the same matrix A (row-major order). */
inline void luFactorize(std::vector<double> &A, size_t N) {
    double *data = A.data();

    for (size_t k = 0; k < N; ++k) {
        double *pk = data + k * N;
        double akk = pk[k];               // pivot element A(k,k)

        /* Parallel over the rows that depend on the current pivot column */
        #pragma omp parallel for schedule(static)
        for (size_t i = k + 1; i < N; ++i) {
            double *pi = data + i * N;
            double factor = pi[k] / akk;   // L(i,k)
            pi[k] = factor;                // store L

            /* Update the remaining RHS elements in the row (i,k+1..N-1) */
            double *pik = pi + k + 1;
            double *pkj = pk + k + 1;
            size_t n = N - (k + 1);

            for (size_t t = 0; t < n; ++t) {
                pik[t] -= factor * pkj[t];
            }
        }
    }
}
