#include <cstddef>
#include <omp.h>
#include <immintrin.h>

/*
   Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix.
   All matrices are stored in row-major format.

   The function preserves the original semantics of accumulating into C.
   It is highly optimised for a modern x86‑64 processor with 8 hardware
   threads, using:
   •  cache‑friendly blocking
   •  SIMD (AVX2) inner‑loops
   •  OpenMP parallelisation
   •  pointer arithmetic to minimise index calculations
*/
inline void gemm(const std::vector<double> &A,
                 const std::vector<double> &B,
                 std::vector<double>       &C,
                 const size_t M, const size_t K, const size_t N)
{
    // Block sizes chosen empirically for a typical 8‑core system
    // Block the rows of A and columns of B to keep working set < L3 cache
    constexpr size_t BLOCK_M = 64;
    constexpr size_t BLOCK_N = 128;
    constexpr size_t BLOCK_K = 64;

    // Ensure C is initialised to zero before use (harness may pre‑zero it)
    // but we honour the accumulation behaviour: no overwrite, only add.
    // Hence we rely on the caller to set C appropriately.

    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t ii = 0; ii < M; ii += BLOCK_M)
    for (size_t jj = 0; jj < N; jj += BLOCK_N)
    {
        const size_t i_max = std::min(ii + BLOCK_M, M);
        const size_t j_max = std::min(jj + BLOCK_N, N);

        for (size_t kk = 0; kk < K; kk += BLOCK_K)
        {
            const size_t k_max = std::min(kk + BLOCK_K, K);

            // Pointers to the current blocks
            const double *restrict a_block = A.data() + ii * K + kk;
            const double *restrict b_block = B.data() + kk * N + jj;
            double       *restrict c_block = C.data() + ii * N + jj;

            for (size_t i = ii; i < i_max; ++i)
            {
                const double *restrict arow = a_block + (i - ii) * K;
                double       *restrict crow = c_block + (i - ii) * N;

                for (size_t k = kk; k < k_max; ++k)
                {
                    const double aik = arow[k - kk];

                    // Use AVX2 to multiply aik by an entire row of B
                    size_t j = jj;
                    for (; j + 4 <= j_max; j += 4)
                    {
                        __m256d b_vals = _mm256_loadu_pd(b_block + (k - kk)*N + (j - jj));
                        __m256d c_vals = _mm256_loadu_pd(crow + (j - jj));
                        __m256d prod    = _mm256_mul_pd(_mm256_set1_pd(aik), b_vals);
                        c_vals = _mm256_add_pd(c_vals, prod);
                        _mm256_storeu_pd(crow + (j - jj), c_vals);
                    }
                    // scalar tail
                    for (; j < j_max; ++j)
                    {
                        crow[j - jj] += aik * b_block[(k - kk)*N + (j - jj)];
                    }
                }
            }
        }
    }
}
