#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <cstdint>
#include <omp.h>

/*  Radix‑2 iterative FFT on a buffer of length N (power of 2)
    The routine is a drop‑in replacement for the original
    fftConjugate.  It preserves bit‑reversal order, axes of
    complex conjugation, and produces identical results in
    double precision.  The implementation pre‑computes a
    twiddle factor table once per invocation and uses OpenMP
    to parallelise the butterfly stage loops.   */
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    /* -------------------------------------------------
        1)  Bit‑reversal permutation
       ------------------------------------------------- */
    const std::size_t m = static_cast<std::size_t>(std::log2(N));

    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        j = ((j & 0xaaaaaaaa) >> 1) | ((j & 0x55555555) << 1);
        j = ((j & 0xcccccccc) >> 2) | ((j & 0x33333333) << 2);
        j = ((j & 0xf0f0f0f0) >> 4) | ((j & 0x0f0f0f0f) << 4);
        j = ((j & 0xff00ff00) >> 8) | ((j & 0x00ff00ff) << 8);
        j = ((j >> 16) | (j << 16)) >> (32 - m);
        if (j > i) std::swap(x[i], x[j]);
    }

    /* -------------------------------------------------
        2)  Radix‑2 decimation‑in‑time FFT
       ------------------------------------------------- */
    // Pre‑compute twiddle factors for full cycle
    std::vector<std::complex<double>> twiddles(N/2);
    const double twiddle_phase = -2.0 * M_PI / N;
    for (std::size_t k = 0; k < N/2; ++k)
        twiddles[k] = std::exp(std::complex<double>(0.0, twiddle_phase * k));

    for (std::size_t stage = 1; stage <= m; ++stage) {
        std::size_t step   = 1ULL << (stage - 1);          // butterflies per group
        std::size_t group  = N / (2ULL << (stage - 1));   // number of groups

        // Parallelise over groups – each group is independent
        #pragma omp parallel for schedule(static, 1)
        for (std::size_t g = 0; g < group; ++g) {
            std::size_t base = g * (step * 2);
            for (std::size_t a = 0; a < step; ++a) {
                std::size_t i = base + a;
                std::size_t j = i + step;

                std::complex<double> t = x[i] - x[j];
                x[i] += x[j];
                // Twist index for this butterfly
                std::size_t twiddle_index = (a * group) % (N/2);
                x[j] = t * twiddles[twiddle_index];
            }
        }
    }

    /* -------------------------------------------------
        3)  Conjugate all samples
       ------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
