#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Simulate one generation of the Game of Life.
 *   input  - NxN grid (row-major) of 0/1 cells.
 *   output - NxN result grid.
 *
 * The function is fully parallelised with OpenMP and uses
 * pointer arithmetic for maximum throughput.  No changes
 * to behaviour are made – the algorithm and the resulting
 * values remain identical to the reference implementation.
 */
inline void gameOfLife(
    std::vector<int> const& input,
    std::vector<int> &output,
    std::size_t N
) {
    /* Fast short‑names for the underlying raw data */
    const int*  in  = input.data();
    int*        out = output.data();
    const std::size_t stride = N;

    /* Treat edges separately to avoid bounds checks in the main loop. */
    /* ---------- First and last rows ---------- */
    #pragma omp parallel for
    for (std::size_t j = 0; j < N; ++j) {
        std::size_t idx = j;                 /* (0,j) */
        int sum = in[idx - stride < 0 ? 0 : idx - stride]   /* none */
                + in[idx + stride < N*N ? idx + stride : 0]   /* below */
                + in[(idx % stride) == 0        ? 0 : idx - 1] /* left */
                + in[(idx % stride) == stride-1? 0 : idx + 1] /* right */
                + in[((idx % stride) == 0)      ? 0 : idx - stride - 1] /* nw */
                + in[((idx % stride) == 0)      ? 0 : idx - stride + 1] /* ne */
                + in[((idx % stride) == stride-1)? 0 : idx + stride - 1] /* sw */
                + in[((idx % stride) == stride-1)? 0 : idx + stride + 1]; /* se */

        int cur = in[idx];
        out[idx] = (cur && (sum==2||sum==3)) || (!cur && sum==3) ? 1 : 0;
    }

    /* ---------- Middle rows (avoid per‑row boundary check) ---------- */
    #pragma omp parallel for collapse(2)
    for (std::size_t i = 1; i + 1 < N; ++i) {
        for (std::size_t j = 1; j + 1 < N; ++j) {
            std::size_t idx = i * stride + j;
            int sum =  in[idx - stride]       /* up   */
                    + in[idx + stride]       /* down */
                    + in[idx - 1]            /* left */
                    + in[idx + 1]            /* right */
                    + in[idx - stride - 1]   /* up-left   */
                    + in[idx - stride + 1]   /* up-right  */
                    + in[idx + stride - 1]   /* down-left */
                    + in[idx + stride + 1];  /* down-right */

            int cur = in[idx];
            out[idx] = (cur && (sum==2||sum==3)) || (!cur && sum==3) ? 1 : 0;
        }
    }

    /* ---------- Last row ---------- */
    #pragma omp parallel for
    for (std::size_t j = 0; j < N; ++j) {
        std::size_t idx = (N-1)*stride + j;
        int sum =  in[idx - stride]                           /* up */
                + in[idx + stride >= N*N ? 0 : idx + stride]   /* none */
                + in[(idx % stride) == 0        ? 0 : idx - 1] /* left */
                + in[(idx % stride) == stride-1? 0 : idx + 1] /* right */
                + in[((idx % stride) == 0)      ? 0 : idx - stride - 1] /* up-left */
                + in[((idx % stride) == 0)      ? 0 : idx - stride + 1] /* up-right */
                + in[((idx % stride) == stride-1)? 0 : idx + stride - 1] /* none */
                + in[((idx % stride) == stride-1)? 0 : idx + stride + 1];/* none */

        int cur = in[idx];
        out[idx] = (cur && (sum==2||sum==3)) || (!cur && sum==3) ? 1 : 0;
    }
}
