#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Return the index of the first even number in the vector x.
   Examples:
   input: [7, 3, 9, 5, 5, 7, 2, 9, 12, 11]
   output: 6
   input: [3, 8, 9, 9, 3, 4, 8, 6]
   output: 1
*/
inline size_t findFirstEven(const std::vector<int>& x) noexcept {
    const size_t n = x.size();
    size_t result = n;                    // sentinel value → “no even number found”

    /* Parallel scan with a min‑reduction. The compiler will keep the code
       simple and the CPU cache friendly.  Branches are evaluated using an
       integer mask to avoid mis‑prediction penalties.  */
    #pragma omp parallel for schedule(static) reduction(min : result)
    for (size_t i = 0; i < n; ++i) {
        // branchless test: even numbers have LSB == 0
        const bool is_even = (static_cast<unsigned>(x[i]) & 1U) == 0U;
        // If even, propose index `i`; otherwise leave `result` unchanged
        if (is_even) {
            // The min reduction guarantees that the smallest i wins.
            // Only write if it could be better than the current value.
            if (i < result) {
                result = i;
            }
        }
    }

    return result;
}
