40_sort_sort_an_array_of_complex_numbers:
```cpp
#pragma once
#include <complex>
#include <vector>
#include <algorithm>
#include <numeric>
#include <cstddef>
#include <omp.h>

/* Sort the vector `x` of complex numbers by their magnitude in ascending order.
   The implementation computes squared magnitudes once, builds an index array,
   performs a parallel quick‑sort on the indices, and finally rearranges
   `x` according to the sorted indices.  The overall behavior and
   semantics match the original code. */
inline void sortComplexByMagnitude(std::vector<std::complex<double>>& x) {
    const std::size_t n = x.size();
    if (n <= 1) return;

    // Compute squared magnitudes in parallel.
    std::vector<double> mag_sq(n);
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        const auto& c = x[i];
        const double r = c.real();
        const double i_ = c.imag();
        mag_sq[i] = r * r + i_ * i_;
    }

    // Prepare index array.
    std::vector<std::size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);

    // Parallel quick‑sort (recursive, using OpenMP tasks).
    const std::size_t THRESHOLD = 1024;  // switch to std::sort for small subarrays
    std::function<void(std::size_t, std::size_t)> qs = [&](std::size_t lo, std::size_t hi) {
        if (hi - lo <= THRESHOLD) {
            std::sort(idx.begin() + lo, idx.begin() + hi,
                      [&](std::size_t a, std::size_t b) { return mag_sq[a] < mag_sq[b]; });
            return;
        }

        // median‑of‑three pivot
        std::size_t mid = lo + ((hi - lo) >> 1);
        std::size_t a = idx[lo];
        std::size_t b = idx[mid];
        std::size_t c = idx[hi - 1];
        if (mag_sq[b] < mag_sq[a]) std::swap(a, b);
        if (mag_sq[c] < mag_sq[a]) std::swap(a, c);
        if (mag_sq[c] < mag_sq[b]) std::swap(b, c);
        std::size_t pivot = a;
        std::swap(idx[mid], idx[hi - 1]);  // move pivot to end

        std::size_t store = lo;
        for (std::size_t i = lo; i < hi - 1; ++i) {
            if (mag_sq[idx[i]] < mag_sq[pivot]) {
                std::swap(idx[store++], idx[i]);
            }
        }
        std::swap(idx[store], idx[hi - 1]);

        // Recursively sort the two partitions in parallel.
        #pragma omp task firstprivate(lo) if (store - lo > THRESHOLD)
        qs(lo, store);
        #pragma omp task firstprivate(store, hi) if (hi - store - 1 > THRESHOLD)
        qs(store + 1, hi);
    };

    #pragma omp parallel
    {
        #pragma omp single
        qs(0, n);
    }

    // Reconstruct sorted vector.
    std::vector<std::complex<double>> temp(n);
    for (std::size_t i = 0; i < n; ++i) temp[i] = x[idx[i]];
    x.swap(temp);
}
